import json
import urllib.request
import urllib.error
import urllib.parse
import hashlib
import re

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Security: Maximum number of enrichment URLs allowed
    MAX_ENRICH_URLS = 3
    # Security: Maximum size of fetched data (1MB)
    MAX_FETCH_SIZE = 1024 * 1024
    # Security: Request timeout
    TIMEOUT = 3
    # Security: Allowed domains whitelist (configure as needed)
    ALLOWED_DOMAINS = [
        'api.example.com',
        'data.example.com',
        'enrichment.example.com'
    ]
    # Security: Maximum redirects
    MAX_REDIRECTS = 2
    
    def is_valid_url(url):
        """Validate URL format and domain"""
        try:
            parsed = urllib.parse.urlparse(url)
            
            # Must be HTTPS
            if parsed.scheme != 'https':
                return False
            
            # Check if domain is in whitelist
            hostname = parsed.hostname
            if not hostname:
                return False
            
            # Check against allowed domains
            domain_allowed = False
            for allowed_domain in ALLOWED_DOMAINS:
                if hostname == allowed_domain or hostname.endswith('.' + allowed_domain):
                    domain_allowed = True
                    break
            
            if not domain_allowed:
                return False
            
            # Prevent SSRF - block private IP ranges
            if re.match(r'^(10\.|172\.(1[6-9]|2[0-9]|3[01])\.|192\.168\.|127\.|169\.254\.|::1|fc00:|fe80:)', hostname):
                return False
            
            # Prevent localhost variations
            if hostname.lower() in ['localhost', '0.0.0.0', '[::]']:
                return False
            
            return True
        except:
            return False
    
    def sanitize_header_value(value):
        """Sanitize header values to prevent injection"""
        # Remove control characters and limit length
        sanitized = re.sub(r'[\x00-\x1f\x7f-\x9f]', '', value)
        return sanitized[:1000]
    
    def fetch_url(url):
        """Fetch URL with security controls"""
        try:
            req = urllib.request.Request(
                url,
                headers={
                    'User-Agent': 'CloudFront-Edge-Enrichment/1.0',
                    'Accept': 'application/json'
                }
            )
            
            # Create opener with redirect handler
            opener = urllib.request.build_opener(
                urllib.request.HTTPSHandler(),
                urllib.request.HTTPRedirectHandler()
            )
            
            response = opener.open(req, timeout=TIMEOUT)
            
            # Check content length before reading
            content_length = response.headers.get('Content-Length')
            if content_length and int(content_length) > MAX_FETCH_SIZE:
                return None
            
            # Read with size limit
            data = response.read(MAX_FETCH_SIZE + 1)
            if len(data) > MAX_FETCH_SIZE:
                return None
            
            return data.decode('utf-8')
        except urllib.error.HTTPError as e:
            # Log error but don't expose details
            return None
        except urllib.error.URLError as e:
            return None
        except Exception as e:
            return None
    
    # Collect enrichment URLs from headers
    enrich_urls = []
    
    # Check for X-Enrich-URL headers (can be multiple)
    if 'x-enrich-url' in headers:
        for header_item in headers['x-enrich-url']:
            url = header_item['value']
            if is_valid_url(url):
                enrich_urls.append(url)
                if len(enrich_urls) >= MAX_ENRICH_URLS:
                    break
    
    # Fetch and aggregate enrichment data
    enrichment_data = {}
    
    for idx, url in enumerate(enrich_urls):
        data = fetch_url(url)
        if data:
            try:
                # Try to parse as JSON
                parsed_data = json.loads(data)
                enrichment_data[f'source_{idx}'] = parsed_data
            except json.JSONDecodeError:
                # Store as raw string if not JSON
                enrichment_data[f'source_{idx}'] = sanitize_header_value(data)
    
    # Add enrichment data to request headers if any data was fetched
    if enrichment_data:
        # Serialize enrichment data
        enrichment_json = json.dumps(enrichment_data)
        
        # Add as custom header (CloudFront has header size limits)
        # Split into chunks if needed (max 10KB per header value)
        MAX_HEADER_SIZE = 10240
        
        if len(enrichment_json) <= MAX_HEADER_SIZE:
            headers['x-enrichment-data'] = [{
                'key': 'X-Enrichment-Data',
                'value': enrichment_json
            }]
        else:
            # If data is too large, create a hash reference instead
            data_hash = hashlib.sha256(enrichment_json.encode()).hexdigest()
            headers['x-enrichment-hash'] = [{
                'key': 'X-Enrichment-Hash',
                'value': data_hash
            }]
            # In production, you would store the full data in a cache (e.g., ElastiCache)
            # and pass only the hash
    
    # Add security headers
    headers['x-enrichment-processed'] = [{
        'key': 'X-Enrichment-Processed',
        'value': 'true'
    }]
    
    # Remove original enrichment URL headers for security
    if 'x-enrich-url' in headers:
        del headers['x-enrich-url']
    
    return request